823             NumDifferences = 2;
824             break;
825           }
826 
827           if (NumDifferences++) break;
828           DiffOperand = i;
829         }
830 
831       if (NumDifferences == 0)   // SAME GEP?
832         return replaceInstUsesWith(I, // No comparison is needed here.
833           ConstantInt::get(I.getType(), ICmpInst::isTrueWhenEqual(Cond)));
