835       else if (NumDifferences == 1 && CanFold(NW)) {
836         Value *LHSV = GEPLHS->getOperand(DiffOperand);
837         Value *RHSV = GEPRHS->getOperand(DiffOperand);
838         return NewICmp(NW, LHSV, RHSV);
