6981 /// If we have an icmp le or icmp ge instruction with a constant operand, turn
6982 /// it into the appropriate icmp lt or icmp gt instruction. This transform
6983 /// allows them to be folded in visitICmpInst.
6984 static ICmpInst *canonicalizeCmpWithConstant(ICmpInst &I) {
6985   ICmpInst::Predicate Pred = I.getPredicate();
6986   if (ICmpInst::isEquality(Pred) || !ICmpInst::isIntPredicate(Pred) ||
6987       InstCombiner::isCanonicalPredicate(Pred))
6988     return nullptr;
6989 
6990   Value *Op0 = I.getOperand(0);
6991   Value *Op1 = I.getOperand(1);
6992   auto *Op1C = dyn_cast<Constant>(Op1);
6993   if (!Op1C)
6994     return nullptr;
6995 
6996   auto FlippedStrictness =
6997       InstCombiner::getFlippedStrictnessPredicateAndConstant(Pred, Op1C);
6998   if (!FlippedStrictness)
6999     return nullptr;
7000 
7001   return new ICmpInst(FlippedStrictness->first, Op0, FlippedStrictness->second);
